css:
/* ✅ Blue border for ALL tables in this Print Format */
.print-format table {
  width: 100%;
  border-collapse: collapse !important;
}

/* border = 1px blue */
.print-format table,
.print-format th,
.print-format td {
  border: 1px solid #FF5A5A !important;
}

/* optional: make header bold */
.print-format th {
  font-weight: 700;
}
